mapper.update:
update clazz
name=#{name}, room=#{room}, begin_date=#{beginDate}, end_date=#{endDate}, master_id=#{masterId}, subject=#{subject}, update_time=#{updateTime}
where id = #{id}

mapper.select:
select c.id clazzId, count(s.id) count from clazz c left join student s on c.id = s.clazz_id where c.id in
#{id}
group by c.id order by count
